-- HRANA
INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('hrana', 'riba-s-gradela', 1, 'de',
 'Gegrillter Fisch und der Geist der Konoba',
 'Auf diesen Inseln kommt der Fisch nicht aus dem Kühlschrank — er kommt aus dem Meer, das Sie beim Essen betrachten. Konoba Mureta auf Pašman, Udica in Kukljica, Kiss bei Neviđane: jede hat ihren eigenen Steg, ihre eigene Geschichte und ihren eigenen Oktopus unter der Peka. Sie setzen sich an einen Steintisch, bestellen, was die Fischer heute Morgen gebracht haben, und begreifen, dass dies der Grund ist, warum Sie gekommen sind.',
 '/api/img/food-grilled-fish',
 '[{"src":"/api/img/food-calamari-fries","alt":"Gebratene Calamari"},{"src":"/api/img/food-seafood-platter","alt":"Meeresfrüchte-Platte"},{"src":"/api/img/food-grilled-prawns","alt":"Gegrillte Garnelen"}]');

INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('hrana', 'maslinovo-ulje', 2, 'de',
 'Olivenöl — das flüssige Gold Ugljans',
 'Ugljan trägt den Spitznamen "Oliveninsel" aus gutem Grund: über 200.000 Bäume, eine zweitausendjährige Tradition und Öl, das als das beste Kroatiens gilt. Hier ist Olivenöl kein Gewürz — es ist die Grundlage von allem. Gießen Sie es über frischen Fisch, tunken Sie Brot ein, träufeln Sie es über Inseltomaten. Besuchen Sie Familienbetriebe und probieren Sie Öl direkt aus der Presse.',
 '/api/img/food-peka-fireplace',
 '[{"src":"/api/img/food-peka-embers","alt":"Peka auf Glut"},{"src":"/api/img/food-meat-buckwheat","alt":"Fleisch mit Buchweizen"},{"src":"/api/img/food-steak-gnocchi","alt":"Steak mit Gnocchi"}]');

INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('hrana', 'dalmatinski-ritual', 3, 'de',
 'Essen als Ritual, nicht als Pflicht',
 'In Dalmatien isst man nicht — man genießt. Das Mittagessen dauert zwei Stunden, beginnt mit marinierten Sardellen und Brudet, geht über zu gegrilltem Fisch und endet mit Johannisbrot oder Feigen in Honig. Zwischen jedem Bissen — das Meer, Gespräche, ein Glas Pošip. Hier schaut niemand auf die Uhr. Das Meer wartet, der Abend ist lang, und der Tisch kann immer verlängert werden.',
 '/api/img/food-sharing-platter',
 '[{"src":"/api/img/food-seafood-beer","alt":"Meeresfrüchte mit Bier"},{"src":"/api/img/food-fish-stew","alt":"Fischeintopf"},{"src":"/api/img/food-beer-seaside","alt":"Bier am Meer"}]');

INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('hrana', 'trznice-i-namirnice', 4, 'de',
 'Vom Markt auf den Tisch',
 'Den frischesten Fisch kaufen Sie im Morgengrauen, direkt vom Boot in Kali — der Fischerhauptstadt der Adria. Auf dem Fischmarkt in Zadar wählen Sie aus Dutzenden Sorten frischem Fisch und Muscheln. Auf der Insel hat jedes Dorf seinen kleinen Laden für das Nötigste, und zum richtigen Einkaufen besuchen Sie Zadar. Und unbedingt: Eis bei Hajduk in Kukljica. Jedes Mal.',
 '/api/img/food-octopus-tomatoes',
 '[{"src":"/api/img/food-pizza","alt":"Pizza"},{"src":"/api/img/food-ice-cream","alt":"Eis"},{"src":"/api/img/food-calamari-squid","alt":"Calamari"}]');

-- AKTIVNOSTI
INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('aktivnosti', 'staze-i-vidikovci', 1, 'de',
 'Wege, die zum Himmel führen',
 'Vom Gipfel des Veliki Bokolj (274 m) sieht Pašman aus wie ein Modell, übersät mit Olivenhainen, und der Velebit erhebt sich hinter dem Meer wie eine Mauer einer anderen Welt. Der Aufstieg beginnt in Dobropoljana — auf einem Schotterweg, der zu Fuß, mit dem Rad oder dem Auto erreichbar ist. Oben erwartet Sie ein runder Steinaussichtspunkt mit Panoramateleskop und Blick auf den Vranasee, die Kornaten und den gesamten Zadar-Archipel.',
 '/api/img/island-hilltop-panorama',
 '[{"src":"/api/img/island-hiking-trail","alt":"Wanderweg"},{"src":"/api/img/island-hilltop-seaview","alt":"Meerblick vom Gipfel"},{"src":"/api/img/island-archipelago-panorama","alt":"Archipel-Panorama"}]');

INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('aktivnosti', 'biciklizam', 2, 'de',
 'Zwei Inseln, zwei Räder',
 'Die Brücke Ždrelac hat einen Radweg, was bedeutet, dass Sie mit einem Fahrrad sowohl Pašman als auch Ugljan erkunden können — 46 Kilometer abwechslungsreiches Gelände, von Küstenstraßen am Meer bis zu Schotterwegen durch Olivenhaine. Die leichtere Route 8 führt durch alle Dörfer der Insel, die anspruchsvollere Route 7 durchquert die Inselmitte. E-Bike-Touren organisiert ZZUUM, Fahrradverleih ab 10 EUR/Tag mit Lieferung.',
 '/api/img/island-stone-arches',
 '[{"src":"/api/img/island-fortress-bay","alt":"Festung über der Bucht"},{"src":"/api/img/island-beach-entrance","alt":"Strandweg"},{"src":"/api/img/island-sunset-coast","alt":"Sonnenuntergang an der Küste"}]');

INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('aktivnosti', 'kornati-i-telascica', 3, 'de',
 'Kornaten und Telašćica — eine Kathedrale aus Fels und Meer',
 'Tagesausflüge starten von Tkon und Kukljica zu den zwei schönsten Destinationen der Adria. Der Nationalpark Kornaten — 89 Inseln, verstreut über das Meer wie Spuren eines urzeitlichen Riesen — raubt selbst erfahrenen Reisenden den Atem. Der Naturpark Telašćica verbirgt den Salzsee Mir, 161 Meter hohe Steilklippen und Buchten, in denen man unter Sternen ankert. Ein Tagesausflug mit Mittagessen an Bord ab 40-50 EUR.',
 '/api/img/island-blue-bay-sailboats',
 '[{"src":"/api/img/island-dramatic-sunset","alt":"Dramatischer Sonnenuntergang"},{"src":"/api/img/island-beach-cove","alt":"Bucht"},{"src":"/api/img/island-crystal-sea","alt":"Kristallklares Meer"}]');

INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('aktivnosti', 'more-i-voda', 4, 'de',
 'Die Umarmung des Meeres',
 'Pašman hat das sauberste Meer der Adria — der ständige Strömungsaustausch hält es kristallklar. Ein Kajak bringt Sie in Buchten, die auf dem Landweg unerreichbar sind. SUP auf dem ruhigen Morgenmeer, wenn die Oberfläche wie Glas ist und die Sonne gerade aufgeht, ist einer jener Momente, die man nicht fotografiert — nur fühlt. Zum Tauchen verbirgt die Unterwasserwelt reiche Artenvielfalt.',
 '/api/img/island-beach-boats',
 '[{"src":"/api/img/island-sandy-beach","alt":"Sandstrand"},{"src":"/api/img/island-kids-beach","alt":"Kinder am Strand"},{"src":"/api/img/island-child-beach","alt":"Kind im Meer"}]');

-- PLAZE
INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('plaze', 'zdrelac-kupanje', 1, 'de',
 'Buchten von Ždrelac — das Meer vor der Tür',
 'Baden in Ždrelac ist spontan: Handtuch nehmen, fünf Minuten gehen und eintauchen. Der Strand Matlovac im Norden ist sandig mit flachem Einstieg ins Meer, einer Strandbar und Spielplatz — perfekt für Familien mit kleinen Kindern. Die Bucht Soline bewahrt mineralreichen Sand, von dem die Fischer sagen, er heile müde Gelenke. Und der Pinienwald im Ortszentrum schafft ein Mikroklima aus Meer- und Harzduft.',
 '/api/img/island-family-beach',
 '[{"src":"/api/img/island-wide-beach","alt":"Breiter Strand"},{"src":"/api/img/island-kids-beach","alt":"Kinder am Strand"},{"src":"/api/img/island-beach-cove","alt":"Bucht"}]');

INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('plaze', 'pasman-plaze', 2, 'de',
 'Sandstrände von Pašman',
 'Entlang der gesamten Insel reihen sich Sandbuchten, umgeben von Tamarisken und Pinien. Banj, nur wenige Kilometer von Ždrelac entfernt, hat flaches Wasser und feinen Sand, ideal für die jüngsten Schwimmer. Lokva in Neviđane bietet den Schatten jahrhundertealter Tamarisken. Mrljane erstreckt sich an einem langen Strand mit Blick auf das herzförmige Galešnjak — die einzige natürlich geformte Herzinsel der Welt.',
 '/api/img/island-sandy-beach',
 '[{"src":"/api/img/island-child-beach","alt":"Kind am Strand"},{"src":"/api/img/island-beach-entrance","alt":"Strandweg"},{"src":"/api/img/island-crystal-sea","alt":"Kristallklares Meer"}]');

INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('plaze', 'ugljan-plaze', 3, 'de',
 'Von Ugljan ins Türkis',
 'Überqueren Sie die Brücke und eine neue Küste eröffnet sich. Jaz in Preko trägt die Blaue Flagge und bietet alles — von Sonnenschirmen und Liegen bis zu Wasserrutschen für Kinder und Beachvolleyball. Sabuša in Kukljica, sandig mit Blick auf Dugi Otok, liegt fünfzehn Gehminuten vom Zentrum entfernt. Mostir im Dorf Ugljan lockt zum Schnorcheln im kristallklaren Wasser.',
 '/api/img/island-beach-boats',
 '[{"src":"/api/img/island-blue-bay-sailboats","alt":"Segelboote in der Bucht"},{"src":"/api/img/island-marina","alt":"Marina"},{"src":"/api/img/island-village-harbor","alt":"Dorfhafen"}]');

INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('plaze', 'skrivene-uvale', 4, 'de',
 'Geheimnisse für Suchende',
 'Die besten Buchten haben keinen Namen auf Google Maps. Manche erreicht man per Kajak, andere durch Olivenhaine, durch die niemand geht. Die Südseite von Pašman ist wild und felsig — hier schlägt das Meer gegen die Felsen und bildet Türkisbecken, die nur Ihnen gehören. Prtljug in Lukoran ist eine Kiesbucht von nur 40 Metern Länge, ohne Einrichtungen, ohne Menschen, ohne alles außer dem Meer.',
 '/api/img/island-dramatic-sunset',
 '[{"src":"/api/img/island-hilltop-seaview","alt":"Meerblick"},{"src":"/api/img/island-archipelago-panorama","alt":"Archipel-Panorama"},{"src":"/api/img/island-sunset-coast","alt":"Sonnenuntergang"}]');

-- ZDRELAC
INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('zdrelac', 'most-i-prolaz', 1, 'de',
 'Eine Brücke zwischen zwei Welten',
 'Die Brücke Ždrelac ist die einzige Landverbindung zwischen Pašman und Ugljan — eine Bogenbrücke, 210 Meter lang, 2009 mit einem Stahlbogen von 68 Metern Spannweite renoviert. Unter ihr, durch die Meerenge Ždrilo, passieren täglich Hunderte von Booten. Am Abend, wenn die Sonne hinter dem Zadar-Archipel versinkt und den Himmel in Rosa und Orange taucht, ist der Blick von der Brücke einer jener Momente, die Sie auf die Insel zurückbringen.',
 '/api/img/island-zdrelac-harbor',
 '[{"src":"/api/img/island-village-harbor","alt":"Hafen Ždrelac"},{"src":"/api/img/island-dramatic-sunset","alt":"Sonnenuntergang"}]');

INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('zdrelac', 'selo-i-dusa', 2, 'de',
 'Ein Dorf aus Stein und Salz',
 'Ždrelac ist die größte Siedlung auf Pašman, aber es fühlt sich an, als liefe die Zeit hier langsamer. Das alte Steinzentrum mit engen Gassen und traditioneller dalmatinischer Architektur bewahrt den Geist der Insel. Die Kirche des Hl. Lukas aus dem 13. Jahrhundert steht im Herzen des Dorfes, und der kleine Hafen im Zentrum dient noch immer den Fischern, die vor der Morgendämmerung hinausfahren.',
 '/api/img/island-pine-chapel',
 '[{"src":"/api/img/island-stone-arches","alt":"Steinbögen"},{"src":"/api/img/island-fortress-bay","alt":"Festung über der Bucht"}]');

INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('zdrelac', 'ribari-i-more', 3, 'de',
 'Menschen des Meeres',
 'Ždrelac war schon immer ein Fischerdorf. Nachts fahren sie mit Lampen zum Tintenfischfang in die Meerenge Ždrilo, morgens kehren sie mit dem Fang zurück, der auf dem Grill oder im Brudet landet. Die Fischerkultur ist hier keine Touristenattraktion — es ist eine Lebensweise, die von Generation zu Generation weitergegeben wird. Im Hafen können Sie Fisch direkt vom Boot kaufen.',
 '/api/img/island-beach-boats',
 '[{"src":"/api/img/island-marina","alt":"Marina"},{"src":"/api/img/island-sunset-coast","alt":"Sonnenuntergang an der Küste"}]');

INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('zdrelac', 'maslinici-i-staze', 4, 'de',
 'Olivenhaine, Pinien und der Weg zum Meer',
 'Hinter dem Dorf beginnt ein anderes Ždrelac: Olivenhaine, die die Hügel hinaufklettern, Pinienwälder mit Harzduft und Pfade zu verborgenen Buchten. Ein 13 Kilometer langer Erholungs- und Lehrpfad verbindet den Gipfel des Bokolj mit der Bucht Soline und führt durch einheimische mediterrane Vegetation. Jeder Schritt bietet eine neue Perspektive — Meerblick auf der einen Seite, Olivenhaine auf der anderen, und eine Stille, die man auf dem Festland nicht hören kann.',
 '/api/img/island-hiking-trail',
 '[{"src":"/api/img/island-hilltop-panorama","alt":"Panorama vom Gipfel"},{"src":"/api/img/island-hilltop-seaview","alt":"Meerblick vom Gipfel"}]');

-- DOLAZAK
INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('dolazak', 'autom-i-trajektom', 1, 'de',
 'Mit dem Auto ans Meer — zwei Fähren, ein Ziel',
 'Zwei Routen führen nach Ždrelac. Die klassische: Autobahn A1 nach Biograd na Moru, dann Jadrolinija-Fähre nach Tkon (25 Minuten, Abfahrten alle 1-2 Stunden). Von Tkon fahren Sie 15 km über die Insel nach Ždrelac. Die Alternative: Autobahn nach Zadar, Fähre Zadar-Preko auf Ugljan (25 Minuten, häufige Abfahrten), dann 15 km über Ugljan und die Brücke Ždrelac direkt zu uns. Beide Routen dauern gleich lang — wählen Sie die mit dem besseren Fährplan.',
 '/api/img/island-jadrolinija-ferry',
 '[{"src":"/api/img/island-village-harbor","alt":"Hafen"},{"src":"/api/img/island-zdrelac-harbor","alt":"Ždrelac Hafen"}]');

INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('dolazak', 'bez-auta', 2, 'de',
 'Ohne Auto — Inselfreiheit',
 'Sie brauchen kein Auto. Vom <a href="https://www.zadar-airport.com" target="_blank" rel="noopener">Flughafen Zadar</a> (ZAD) sind es 15 Minuten mit Bus oder Taxi in die Stadt. Von Zadar fährt stündlich eine Fähre nach Preko, und von Preko bis zur Brücke Ždrelac sind es 15 km — ein Lokalbus oder organisierter Transport bringt Sie zur Tür. Auf der Insel beginnt der Fahrradverleih ab 10 EUR/Tag mit Lieferung.',
 '/api/img/island-beach-entrance',
 '[{"src":"/api/img/island-sandy-beach","alt":"Sandstrand"},{"src":"/api/img/island-family-beach","alt":"Familienstrand"}]');

INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('dolazak', 'savjeti-za-put', 3, 'de',
 'Bevor Sie losfahren',
 'Überprüfen Sie den Fährplan auf <a href="https://www.jadrolinija.hr" target="_blank" rel="noopener">jadrolinija.hr</a> — im Sommer sind die Abfahrten häufiger, aber an Wochenenden und Feiertagen können die Fähren voll sein, daher ist frühes Kommen ratsam. Der Parkplatz am Terminal in Biograd ist geräumig und günstig. Die Brücke Ždrelac ist kostenlos und rund um die Uhr geöffnet. Bei Ankunft in der Ferienwohnung: Schuhe aus, Fenster auf, einatmen — der Duft von Salz, Pinien und Lavendel sagt Ihnen, dass Sie angekommen sind.',
 '/api/img/island-wide-beach',
 '[{"src":"/api/img/island-crystal-sea","alt":"Kristallklares Meer"},{"src":"/api/img/island-archipelago-panorama","alt":"Archipel-Panorama"}]');

-- VODIC
INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('vodic', 'pasman-sela', 1, 'de',
 'Pašman — zehn Dörfer, eine Seele',
 'Pašman hat die größte Grünfläche im gesamten kroatischen Archipel — zehn Dörfer, verteilt auf 60 km Insel, jedes mit eigenem Charakter. Ždrelac an der Spitze bewahrt den Fischergeist, Dobropoljana liegt am Fuße des Bokolj mit den schönsten Sonnenuntergängen, Neviđane verbirgt eine Steinfigur des Hl. Michael aus dem 12. Jahrhundert. In Tkon, dem Fährhafen, ist das Benediktinerkloster auf dem Ćokovac seit 1129 ununterbrochen aktiv.',
 '/api/img/island-hilltop-panorama',
 '[{"src":"/api/img/island-village-harbor","alt":"Dorfhafen"},{"src":"/api/img/island-pine-chapel","alt":"Kapelle in den Pinien"},{"src":"/api/img/island-family-beach","alt":"Familienstrand"},{"src":"/api/img/island-sunset-coast","alt":"Sonnenuntergang"}]');

INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('vodic', 'ugljan-sela', 2, 'de',
 'Ugljan — die grüne Oliveninsel',
 'Ugljan, durch die Brücke bei Ždrelac mit Pašman verbunden, trägt den Spitznamen "Grüne Insel" — über 200.000 Olivenbäume und eine zweitausendjährige Tradition. Preko ist das Verwaltungszentrum mit romantischer Uferpromenade und Fähre nach Zadar (25 Min). Über Preko bietet die Festung des Hl. Michael auf 265 m einen atemberaubenden Blick. Kali ist die Fischerhauptstadt, Kukljica das Gastrozentrum mit Konoba Udica und den schönsten Stränden.',
 '/api/img/island-fortress-bay',
 '[{"src":"/api/img/island-stone-arches","alt":"Steinbögen"},{"src":"/api/img/island-beach-boats","alt":"Strand mit Booten"},{"src":"/api/img/island-marina","alt":"Marina"},{"src":"/api/img/island-beach-cove","alt":"Bucht"}]');

INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('vodic', 'zadar', 3, 'de',
 'Zadar — die Stadt, die dem Meer Musik spielt',
 'Eine 25-minütige Fähre von Preko bringt Sie in die Stadt, die Alfred Hitchcock 1964 zum Ort des schönsten Sonnenuntergangs der Welt erklärte. An der Zadar-Uferpromenade verwandelt die Meeresorgel von Architekt Nikola Bašić Wellen in Musik — Marmorstufen steigen ins Meer hinab, und jede Welle drückt Luftkammern, die überirdische Klänge erzeugen. Daneben verwandelt der Sonnengruß — ein 22 Meter großer Glaskreis mit Solarzellen — nachts Sonnenenergie in eine hypnotische Lichtshow.',
 '/api/img/zadar-colorful-rooftops',
 '[{"src":"/api/img/zadar-riva-promenade","alt":"Zadar Uferpromenade"},{"src":"/api/img/zadar-old-town-street","alt":"Altstadtgasse"},{"src":"/api/img/zadar-harbor-panorama","alt":"Hafenpanorama"},{"src":"/api/img/zadar-bell-tower","alt":"Glockenturm"}]');

INSERT INTO ec_editorial (page_key, section_key, sort_order, locale, title, body, image, gallery) VALUES
('vodic', 'izleti-s-otoka', 4, 'de',
 'Tagesausflüge — Kornaten, Telašćica, Vranasee',
 'Von Pašman und Ugljan starten Ausflüge, die die wilde Seite der Adria enthüllen. Der Nationalpark Kornaten — 89 Inseln, im Meer verstreut wie eine kosmische Folge — ist als Tagesausflug von Tkon oder Kukljica erreichbar (ab 40-50 EUR mit Mittagessen an Bord). Der Naturpark Telašćica verbirgt den Salzsee Mir und 161 m hohe Klippen. Auf dem Festland ist der Vranasee — Kroatiens größter natürlicher See — ein Paradies für Vogelbeobachter und Radfahrer.',
 '/api/img/island-blue-bay-sailboats',
 '[{"src":"/api/img/island-dramatic-sunset","alt":"Sonnenuntergang"},{"src":"/api/img/island-crystal-sea","alt":"Kristallklares Meer"},{"src":"/api/img/island-archipelago-panorama","alt":"Archipel-Panorama"}]');
